        ed = False
    if start_date is not None and start_date > extracted_date:
        now = datetime.now()
        if extracted_date.month < now.month and extracted_date.year == now.year:
            extracted_date = extracted_date.replace(year=extracted_date.year + 1)
        else:
            return False
    if end_date is not None and end_date < extracted_date:
